cat > /tmp/inspect_mcp.cs << 'EOF'
using System;
using System.Reflection;
using System.Linq;

// Load the assemblies
var mcp = Assembly.LoadFrom("/home/runner/.nuget/packages/modelcontextprotocol/1.2.0/lib/net10.0/ModelContextProtocol.dll");
var mcpAspNetCore = Assembly.LoadFrom("/home/runner/.nuget/packages/modelcontextprotocol.aspnetcore/1.2.0/lib/net10.0/ModelContextProtocol.AspNetCore.dll");
var mcpCore = Assembly.LoadFrom("/home/runner/.nuget/packages/modelcontextprotocol.core/1.2.0/lib/net10.0/ModelContextProtocol.Core.dll");

Console.WriteLine("=== ModelContextProtocol.AspNetCore Public Types ===\n");
foreach (var type in mcpAspNetCore.GetExportedTypes().OrderBy(t => t.Name))
{
    Console.WriteLine($"Type: {type.FullName}");

    // Show extension methods and public static methods
    var staticMethods = type.GetMethods(BindingFlags.Public | BindingFlags.Static)
        .Where(m => !m.IsSpecialName)
        .OrderBy(m => m.Name);

    foreach (var method in staticMethods)
    {
        var parameters = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  static {method.ReturnType.Name} {method.Name}({parameters})");
    }

    // Show public instance methods (excluding inherited)
    var instanceMethods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName)
        .OrderBy(m => m.Name);

    foreach (var method in instanceMethods)
    {
        var parameters = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {method.ReturnType.Name} {method.Name}({parameters})");
    }

    // Show public properties
    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
    foreach (var prop in props.OrderBy(p => p.Name))
    {
        Console.WriteLine($"  {prop.PropertyType.Name} {prop.Name} {{ {(prop.CanGet ? "get;" : "")} {(prop.CanSet ? "set;" : "")} }}");
    }

    Console.WriteLine();
}

Console.WriteLine("\n=== ModelContextProtocol Public Types ===\n");
foreach (var type in mcp.GetExportedTypes().Where(t => t.Namespace != null && (t.Namespace.Contains("Attributes") || t.Name.Contains("Tool") || t.Name.Contains("Resource"))).OrderBy(t => t.Name))
{
    Console.WriteLine($"Type: {type.FullName}");

    // Show attributes
    var attrs = type.GetCustomAttributes(false);
    if (attrs.Length > 0)
    {
        foreach (var attr in attrs)
        {
            Console.WriteLine($"  Attribute: [{attr.GetType().Name}]");
        }
    }

    var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
        .Where(m => !m.IsSpecialName)
        .OrderBy(m => m.Name);

    foreach (var method in methods)
    {
        var parameters = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  {method.ReturnType.Name} {method.Name}({parameters})");
    }

    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly);
    foreach (var prop in props.OrderBy(p => p.Name))
    {
        Console.WriteLine($"  {prop.PropertyType.Name} {prop.Name} {{ {(prop.CanGet ? "get;" : "")} {(prop.CanSet ? "set;" : "")} }}");
    }

    Console.WriteLine();
}

Console.WriteLine("\n=== All Attribute Types in ModelContextProtocol ===\n");
foreach (var type in mcp.GetExportedTypes().Where(t => typeof(Attribute).IsAssignableFrom(t)).OrderBy(t => t.Name))
{
    Console.WriteLine($"[{type.Name}]");

    var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance);
    foreach (var prop in props)
    {
        Console.WriteLine($"  {prop.PropertyType.Name} {prop.Name} {{ get; set; }}");
    }

    var ctors = type.GetConstructors();
    foreach (var ctor in ctors)
    {
        var parameters = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  public {type.Name}({parameters})");
    }

    Console.WriteLine();
}
EOF
