218. 	/// <summary>
219. 	/// Provides methods for formatting and parsing event IDs used by <see cref="T:ModelContextProtocol.Server.DistributedCacheEventStreamStore" />.
220. 	/// </summary>
221. 	/// <remarks>
222. 	/// Event IDs are formatted as "{base64(sessionId)}:{base64(streamId)}:{sequence}".
223. 	/// </remarks>
224. 	internal static class DistributedCacheEventIdFormatter
225. 	{
226. 		private const char Separator = ':';
227. 
228. 		/// <summary>
229. 		/// Formats session ID, stream ID, and sequence number into an event ID string.
230. 		/// </summary>
231. 		public static string Format(string sessionId, string streamId, long sequence)
232. 		{
233. 			string value = Convert.ToBase64String(Encoding.UTF8.GetBytes(sessionId));
234. 			string value2 = Convert.ToBase64String(Encoding.UTF8.GetBytes(streamId));
235. 			return $"{value}{58}{value2}{58}{sequence}";
236. 		}
