238. 		/// <summary>
239. 		/// Attempts to parse an event ID into its component parts.
240. 		/// </summary>
241. 		public static bool TryParse(string eventId, out string sessionId, out string streamId, out long sequence)
242. 		{
243. 			sessionId = string.Empty;
244. 			streamId = string.Empty;
245. 			sequence = 0L;
246. 			ReadOnlySpan<char> source = eventId.AsSpan();
247. 			Span<Range> destination = stackalloc Range[4];
248. 			if (source.Split(destination, ':') != 3)
249. 			{
250. 				return false;
251. 			}
252. 			try
253. 			{
254. 				Range range = destination[0];
